commits.content:
# See https://www.nushell.sh/book/configuration.html
use std/util "path add"
path add "/opt/homebrew/bin"


# setup vendor autoload directory
# mkdir ($nu.data-dir | path join "vendor/autoload")
mkdir ...$nu.vendor-autoload-dirs

# setup user autoload directory
mkdir ...$nu.user-autoload-dirs

# starship - terminal styling
starship init nu | save -f ($nu.data-dir | path join "vendor/autoload/starship.nu")

# mise - tool for managing multiple versions of nushell
mise activate nu | save -f ($nu.data-dir | path join "vendor/autoload/mise.nu")

# carapace - completion
carapace _carapace nushell | save -f ($nu.data-dir | path join "vendor/autoload/carapace.nu")

$env.config = {
  buffer_editor: "code"
  show_banner: false

  rm: {
    always_trash: true
  }
}

# Specifies how environment variables are:
# - converted from a string to a value on Nushell startup (from_string)
# - converted from a value back to a string when running external commands (to_string)
# Note: The conversions happen *after* config.nu is loaded
$env.ENV_CONVERSIONS = {
    "PATH": {
        from_string: { |s| $s | split row (char esep) | path expand --no-symlink }
        to_string: { |v| $v | path expand --no-symlink | str join (char esep) }
    }
    "Path": {
        from_string: { |s| $s | split row (char esep) | path expand --no-symlink }
        to_string: { |v| $v | path expand --no-symlink | str join (char esep) }
    }
}

# Directories to search for scripts when calling source or use
# The default for this is $nu.default-config-dir/scripts
$env.NU_LIB_DIRS = [
    ($nu.default-config-dir | path join 'scripts') # add <nushell-config-dir>/scripts
    ($nu.data-dir | path join 'completions') # default home for nushell completions
]

# Directories to search for plugin binaries when calling register
# The default for this is $nu.default-config-dir/plugins
$env.NU_PLUGIN_DIRS = [
    ($nu.default-config-dir | path join 'plugins') # add <nushell-config-dir>/plugins
]

# Default env variables
$env.DOCKER_BUILDKIT = 1
$env.HELM_EXPERIMENTAL_OCI = 1
$env.HELM_S3_MODE = "3"
$env.VAULT_ADDR = "https://vault.infra.subsplash.io"
